analysis[21] = "【核心逻辑】CNC和注塑共同特点是持续生产效益最高频繁换型是成本杀手。\n\n【200人CNC厂换型代价详解】一台CNC正在生产A型号手机中框换成B型号平板外壳：卸治具15min+装治具20min+调程序10min+首件调试30-60min+首件送检15min=最少1.5-2.5h非生产时间！100台机频繁换型一天产能损失巨大。\n\n注塑厂同理换颜色要洗机白色转黑色不用洗黑色转白色要洗1-2h；换模具更甚上下模+调机至少半天起步。\n\n【所以排产原则同一型号尽量连续生产减少换型次数】"
analysis[22] = "【核心逻辑】KPI是衡量工作成果的量化指标不知道KPI等于不知道怎么考核。\n\n【PMC核心KPI】\n①出货达成率=实际出货÷计划出货×100% 目标≥96% 例计划5000实出4800=96%\n②计划达成率=实际产出÷计划产出×100% 目标≥95% 例计划800实出760=95%\n③工单及时结案率=按时结案÷总工单 目标≥90%\n\n【如何达成】每2小时监控一次发现落产立即追原因；提前识别风险物料/设备/人力；异常升级机制2h未解决→报主管→报经理"
analysis[23] = "【核心逻辑】面试不同类型公司要调整话术强调共性而非差异。\n\n【从CNC厂面试电子厂】CNC厂和电子厂计划跟单原理一样都是根据计划跟进实际产出协调资源解决异常。区别CNC关注机台利用率和刀具寿命电子厂关注SMT贴片良率和测试通过率。但核心能力通用ERP操作Excel数据分析跨部门沟通异常快速响应。而且CNC厂环境更艰苦有夜班有油污噪音大我能适应来电子厂条件更好更能适应\n\n【从注塑厂面试CNC厂】注塑和CNC都是离散制造都需要按计划管控进度。注塑关注成型周期和模具状态CNC关注工序衔接和刀具管理。已掌握跟单核心方法论切换只需1-2周熟悉工艺"
analysis[24] = "【核心逻辑】最好的案例=有冲突+有难度+主动行为+好结果。\n\n【详细版案例】背景月底最后一天客户临时追加2000件急单要求第二天上午发货当时下午4点了正常来不及。\n行动：①立即找生产主管确认哪些机台可以加班②发现3号车间夜班不足打电话请休班员工回来加班承诺双倍工时③自己留到凌晨两点一边跟进一边帮搬运成品到检验区④半夜刀具崩了开车去技术员家里把他接来换刀他家离厂只有10min\n结果凌晨2点半全部完工早上8点准时装车发货客户微信上说这次效率很高感谢配合经理晨会点名表扬\n\n好在哪有数字2000件凌晨2点有细节开车接技术员有结果客户好评+经理表扬"
analysis[25] = "【核心逻辑】设备配置体现你对工厂硬件的了解程度。\n\n【标准回答】我们厂总共有100台左右CNC设备：三轴CNC约占20台18%用于加工精度要求不高的简单产品如支架连接件；四轴CNC约占80台82%用于加工复杂曲面产品如手机中框笔电外壳目前还没有五轴设备五轴一般用于航空医疗消费电子暂时用不上\n\n三轴四轴区别：三轴只能XYZ三个方向运动四轴多了一个旋转轴A轴能加工侧面特征不需要二次装夹效率和精度都更好所以我们大部分产品都用四轴做三轴主要做一些辅助件"
analysis[26] = "【核心逻辑】ERP操作要说具体功能模块越细越真实。\n\n【每日操作清单】每天早上8:30前：①打开金蝶云星空→销售订单明细表→导出今日出货计划 ②打开生产工单列表→筛选今日需完工→检查领料状态\n每天中午12:00前：③采购订单明细表→筛选今日预计到货PO→跟踪物流状态 ④物料采购入库单→确认昨天的到货是否已入库\n每天下午16:00前：⑤生产工单入库单→录入完工数据 ⑥BOM查询→核对明天开工物料是否齐全\n每周四：⑦批量创建下周MO ⑧导出呆滞料报表\n\n【记住不要只说会用ERP要说'我每天用ERP做这些事'】"
analysis[27] = "【核心逻辑】成长轨迹=从小白到专业的进化过程体现学习能力和职业规划。\n\n【7个月学到了什么】\n第1月学会金蝶基本操作查工单查库存录入库\n第2月学会Excel做日报VLOOKUP匹配数据透视分析产量趋势\n第3月理解跟单核心逻辑计划vs实际偏差就是异常异常就要推动解决\n第4月开始接触物料端跟催采购协调仓库备料处理来料异常\n第5月了解CNC工艺流程从铝棒到成品的每道工序时间节点和常见异常\n第6月开始协助经理做简单排产根据产能评估能否接急单\n第7月能够独立处理大部分事务经理开始让我负责几个重要客户的跟单\n\n【最大收获】发现计划部门其实是整个工厂的大脑生产做什么什么时候做什么料做全都由计划驱动这让我对这个岗位有了全新认识也想深入发展下去"
analysis[28] = "【核心逻辑】产能数据要合理经得起推敲。\n\n【产能数据】设备100台CNC三轴20+四轴80\n单台产能取决于产品复杂度：简单产品支架加工约1min/件台时50-60件；中等产品外壳3-5min/件台时12-20件；复杂产品中框8-15min/件台时4-7件\n日产能白夜班22h正常混合排产综合平均25件/h→100×25×22≈55000件；考虑换型停机异常利用率70%实际日均36000-40000件\n月产能36000×26≈90-100万件/月\n\n【回答技巧】给范围不精确数字因为受产品结构和订单波动影响很大"
analysis[29] = "【核心逻辑】组织架构体现你对公司运作体系的理解。\n\n【210人标准架构】总人数约210人\n一线生产约150人72%：CNC操机员80白40+夜40每人看1-2台机；品质151PQC8+IQC3+OQC4；技术/编程20CNC调机编程15+ME维修5\n职能部门约35人17%：计划部2生管1+跟单1即你；采购2+文员1；仓库3管2+物料1；业务5；财人行政约10\n其他约25人12%：工程研发10；厂长副厂长各部门经理约15\n\n【注意人数比例要合理一线通常占60%-75%】"
analysis[30] = "【核心逻辑】爬坡曲线是制造业常识新产线新产品不可能第一天就满产。\n\n【爬坡规律】Day1产能约60%新工人不熟练治具还在调试程序还要优化可能尺寸不稳定频次偏高换刀频繁\nDay2产能约75%工人开始上手技术员优化参数个别机台还是不太稳定\nDay3及以后达标准95%-100%进入稳定期计算正式OEE\n\n【为什么前两天慢】人新工人适应产品和机台；机新装治具有微调空间；法切削参数可能需要优化；料第一批来料可能存在公差波动\n\n【跟单作用】爬坡期间加大巡线频率每小时一次及时发现解决问题"
analysis[31] = "【核心逻辑】提升效率的方法=让人有压力感+让数据透明化。\n\n【实战方法一】每小时产量看板在车间挂白板每小时更新每台机实际产出：#01目标60实际58差-2 #02目标60实际62+2 #03目标60实际45-15←要关注 操机员看到数据和别人的对比自然有竞争意识\n\n方法二班前通报每天早上10min站会通报昨天各机台达标情况优秀的口头表扬落后的提醒注意\n\n注塑厂特殊性注塑全自动机器按参数自动循环人工只负责剪水口和打包效率提升重点不在操机员而在减少停机时间降低不良率缩短辅助作业时间"
analysis[32] = "【核心逻辑】异常处理能力=PMC跟单的核心竞争力要有完整处理SOP。\n\n【三大异常SOP】\n品质异常触发IPQC发现某批次尺寸超差0.02mm→①叫停该机台隔离可疑品约50件 ②拉品质+生产+技术员现场 ③判定偶发还是系统性测最近10件3件超差属系统性 ④A返工超差不大的话 ⑤B让步接受与客户沟通 ⑥C报废重做无法返工也无法让步 ⑦根因分析刀具磨损/程序漂移/材料问题 ⑧防再发增加巡检频次/缩短换刀周期/更换材料批次\n\n设备异常触发#03主轴报警停机→①通知ME诊断预计修复时间 ②<1h前工序继续堆积后续消化 ③>4h调整排产转别的空闲机台 ④>1天停线通知客户调交期\n\n欠料异常触发明天用的D10合金刀只剩5把缺口20把→①查PO供应商已发货司机电话跟踪 ②若延期调整开机时间 ③严重延期寻找替代方案\n\n【核心原则处理完一定要防再发不然反复发生】"
analysis[33] = "【核心逻辑】交不了货=PMC失职但处理方式体现专业度。\n\n【应对链】第一步核实LT是否合理业务给的5天但我们这款光CNC就要3天+表面处理2天+检验1天=6天本身就不合理LT不合理责任不在你但要尽力\n第二步盘点所有可用资源：①成品库存有安全库存救命 ②半成品WIP加速完成 ③瓶颈物料缺什么能不能替代 ④产能增开夜班/周末加班/委外部分工序\n第三步补救方案优先级1调用安全库存 2通用物料备货 3推动客户提供预测 4委外加工 5增开夜班\n第四步如果都做不到带着方案去沟通X经理客户这款确实无法按原定交期最快XX日期给您XX数量剩余XX日期补齐已采取XX措施请问这样可以接受→带着方案去沟通不是带着问题去求助"
analysis[34] = "【核心逻辑】订单评审=接前可行性分析避免盲目承诺无法交付。\n\n【完整流程】Step1接收信息业务发来新产品P007中框5000件T+7\nStep2产能评估当前负荷85%剩余产能15%×100台×22h×25≈8250件余量5000件在能力内OK\nStep3物料评估BOM需Φ65铝棒0.8kg/件共4000kg库存1500kg→缺2500kg在途PO T+3到2000kg→还缺500g风险✗\nStep4对策通知采购加急500kg或从兄弟厂借调或调整排产顺序\nStep5输出可以接单但注意铝棒到货时间建议采购T+2前到位否则影响T+5开机\n\n【如果真的做不到】T+7交5000做不到最快T+10可交4500或T+7先交3000剩T+10补→给客户选择题不是是非题"
analysis[35] = "【核心逻辑】工序平衡是多工序制造的核心难点不平衡就会产生瓶颈浪费。\n\n【实例】P007需3道CNC工序：第1序粗铣50件/h有20台 第2序精铣40件/h有30台←瓶颈 第3序钻攻60件/h有20台\n问题第1太快半成品在第2前堆积第3没活干等\n\n短期当天：第2技术员全部上阵加快调机；从第3抽2台支援第2；第1适当降速不要过多堆积\n中期持续1-2天：增加第2机台数量；培训更多操作员；优化加工程序减时间\n长期：投资更多设备；工艺改进能否合并取消第2序\n\n注塑厂一般是单工序成型不存在多工序平衡问题每台独立运行各自产出各自入库只在辅工段剪水口去毛刺包装的人力匹配上"
analysis[36] = "【核心逻辑】跨部门协调=PMC核心日常工作方法论是多渠道+定时跟进+升级机制。\n\n【场景】#07机台P007连续出现0.03mm超差\n\n①第一时间0min走到机台旁确认拍照留存记录机台号产品号超差值数量\n②多渠道5min内微信群@品质工程师陈工#07机P007超差0.03mm请速来看+同时打电话陈工你在哪马上过来不接打他主管电话\n③现场协同拉陈工品质+老李生产+小王技术员一起看陈工复测确认超差小王查程序刀具老李确认受影响数量三方讨论刀具磨损还是程序漂移\n④定方案并设时限小王你要多久4h→手机设4h后提醒闹钟\n⑤定时跟进4h后小王调好了吗首件测怎样→确认闭环\n\n【很多人只做到第②步就不管了然后事情没人推动了定时跟进才是确保真正解决的关键】"
analysis[37] = "【核心逻辑】计划达成率管控=事前预防+事中监控+事后复盘三级体系。\n\n【一级事前排计划时】每周四下午和经理评审下周计划逐款确认产够不够料齐不齐有无特殊工艺要求有风险的标红旗提前制定预案\n\n二级事中生产中】每2h巡线一次记录每台实际产出vs计划 A型计划200实180落后10%追问原因#05机停40min换刀导致判断能否弥补还剩4h按正常速度可追回或追不回了需调整计划\n\n三级事后次日早上】9:00前完成整体达成率统计分析未达成原因物料/设备/人为因素根据复盘结果调整当天计划昨天A欠产200今天优先补产\n\n【数据说话】通过这套体系计划达成率从最初85%稳定在了96%左右"
analysis[38] = "【核心逻辑】工单管控=从开工到结案的完整生命周期管理。\n\n【实务】创建每周四经理根据销售订单创建MO关联BOM系统自动生成领料需求30台活跃20-30个工单/周\n执行生产部打印领料单→仓库发料→机台生产每日跟进各工单实际vs计划如有异常缺料/设备/品质及时协调\n完结生产完成后3-5个工作日系统结案自动计算投入量vs合格产出vs不良 标准损耗率CNC约4%含试加工调机废品过程报废 注塑约3%\n\n异常处理实际超出BOM很多→分析是BOM不准还是浪费严重；损耗率超标→追查哪个工序/哪台机/哪批料的问题\n\n【不结案的工单持续占用系统资源和物料账目影响库存准确性】"
analysis[39] = "【核心逻辑】产能不达标=人机料法环五个维度逐一排查。\n\n【排查和处理】现象A型标准50件/h实际只有35件/h差30%\n\n维度一标准是否合理？找生产主管和技术员一起实测让熟练工按标准做一小时如果也只能38件→标准定高了重新评定 如果能做到48件→标准没问题是人的问题\n\n维度二人的问题？是新员工→一对一师傅带教 是老员工态度→单独谈话了解原因家事/工资/身体 是高强度疲劳→每小时轮岗休息或增加轮换\n\n维度三环境因素？夏天太热加风扇空调冷饮 噪音大发耳塞 油烟味重加强通风 岗位补贴每月200-300元\n\n【原则先排除标准和环境的客观问题再谈人的主观问题不要一上来就怪员工不努力】"
analysis[40] = "【核心逻辑】防止延期=把问题消灭在萌芽状态而不是火烧眉毛救火。\n\n【防延期体系】为什么一般来说不存在突然延期？因为我每2h巡线任何异常都在萌芽就被发现了。\n\n时间线 08:00复核夜班产出发现A落后8% 08:30找到原因夜班#12机主轴异响停机1h 09:00ME已在修预计10点恢复可控 10:00#12机恢复正常追赶产量 12:00午休前复核A已追回到落后2%下午可赶上 16:00最终复核A达成率98%基本达标\n\n如果解决不了的异常 #12机主轴坏了要等后天新主轴到→第一时间告诉经理#12机主轴损坏影响A产能15%预计影响交期1d→经理决定调整其他机台排产把A的一部分转到#03/#04做 实时更新计划和出货计划通知业务最新预期\n\n【核心让信息流动起来不要让问题隐藏】"
analysis[41] = "【核心逻辑】会不会排产考察你对排产逻辑的理解不是要求你现在完美排产。\n\n【CNC排产逻辑】原则①持续生产优先同型号同一批机台连续做完减少换型损失 ②瓶颈工序优先产能最紧张的优先排满 ③交期优先近的先排 ④物料齐套没料的不要排\n\n实例 订单A中框3000件T+5各15+12+8min B外壳2000件T+7各10+8+5min C支架5000件T+4各3+2+1min\n排产思路 C交期最近且最简单→先用三轴机就够了 A交期T+5且工序最多→排在四轴机上注意第2序精铣是瓶颈 B交期最宽→最后排穿插在AC间隙\n\n注塑排产区别 注塑成型周期固定45s/模 排产主要考虑模具在哪台机台 要不要换颜色洗机时间 模具升温时间 比CNC简单很多"
analysis[42] = "【核心逻辑】物料管理的精细度直接影响生产稳定性。\n\n【概况】物料总数约150-200种SKU 分类：原材料10种不同规格铝棒(Φ65/Φ80/Φ100等)不同牌号(6061/6063/7075)；耗材30-50种各种规格刀具钻头丝锥铰刀切削液等；包材20-30种PE袋气泡膜纸箱标签胶带；刀具类50-80种这是CNC厂物料种类最多的\n供应商约10-15家 铝材2-3家主力1+备份1-2 刀具3-5家不同品类不同供应商 包材/辅料3-5家 切削液1-2家\n\n【跟单重点关注刀具和铝棒的库存和交期这两项缺了产线就直接停了】"
analysis[43] = "【核心逻辑】来料异常的处理方式和严重程度取决于物料类型。\n\n【CNC厂实况】铝材来料异常较少见正规供应商质量很稳定偶尔出现表面划痕→通常不影响CNC加工切削掉表层可让步接收；规格偏差直径大了0.5mm→看在可加工范围内能用的特采；材质问题硬度不够→严重会导致刀具加速磨损必须退回\n制程不良更常见CNC加工过程中产生的不良远多于来料不良 尺寸超差→返工重新加工或打磨修正 表面粗糙度不够→换新刀或调整转速进给 孔位偏移→程序补偿或返工 变形薄壁件易变形→调整夹紧力或增加支撑\n注塑粒子料正规供应商质量非常稳定几乎不会有来料异常 注塑不良几乎100%来自制程"
analysis[44] = "【核心逻辑】来料不良处理=快速决策+减少影响+根因追溯。\n\n【SOP实例】刚到的Φ65×100的6061铝棒IQC检测发现整批200根中有35根不合格\nStep1紧急度判断这批铝棒给P009产品用明天上午要开机→急料\nStep2 MRB召集IQC主管+采购+仓库+我评审 A特供划痕在表面CNC加工时会切削掉不影响最终产品推荐 B返工铝棒没法返工此路不通 C退回供应商需3天会影响交期 D筛选使用165根好的先用35根差的退回→折中方案\nStep3执行选D 165根够生产2天 同时要求供应商紧急补发35根\nStep4调整计划165根约够2天 先安排2天生产 补货后天到 后天的生产按补货到位后安排 通知业务P009前两天正常第三天可能延迟半天\nStep5根因追溯要求供应商给8D报告通常是运输碰撞或仓储堆放不当 要求改善包装或运输方式\n\n【MRB原则在质量和交期间找平衡特采前提是不影响最终产品质量】"
analysis[45] = "【核心逻辑】欠料=PMC最常见的噩梦必须有系统的预防和应对机制。\n\n【六大根因及对策】①计划和物料不同步→ERP设置联动开工单自动生成需求 ②物控运算失误BOM写错量→每月核对BOM准确性 ③手误重要数据双人复核 ④ECN变更未及时释放→建立ECN检查清单 ⑤BOM不准确定期用实际耗用反算 ⑥供应商自身原因开发备选+安全库存+提前下单\n\n【应急措施】①找替代料D10能不能用D8代替可能需调程序 ②找替补供应商主供应出问题了备选救急 ③安全库存通用物料保持3-7天 ④每天复核未来3天到货 ⑤要求供应商提前3-7天到 ⑥终极调整计划+告知客户带方案沟通"
analysis[46] = "【核心逻辑】物料发放流程=ERP驱动的标准化作业确保账实相符。\n\n【完整流程】Step1计划部开立MO20230815001关联P007 BOM系统自动生成领料需求 铝棒160kg D10刀片4片 切削液适量\nStep2通知仓库备料 系统点击下达仓库收到备料单 仓管按单取料核对规格数量 库存不足立即通知我\nStep3生产部打印领料单带单到仓库窗口 仓管核对单据发放实物 双方签字\nStep4系统扣账 铝棒-160kg 刀片-4片 工单领料状态变为已完成\n\n特殊情况 超领实际超BOM→开超领单注明原因 退料生产结束有多余→开退料单退回 代用BOM上的料没有用替代料→系统投料变更"
analysis[47] = "【核心逻辑】跳票=供应商管理失效预防和应对两手抓。\n\n【预防层】①每天早上9点和采购复核未来3天内预计到货PO 张姐PO202308088那批铝棒今天能到吧司机出发了吗 拿到司机电话自己跟踪 ②建微信群/钉钉群 重要物料要求供应商发货后群里通知 ③合同条款延期罚款条款虽有威慑\n\n【应对层】第一次延期1-2天相信供应商理由堵车/天气/车辆故障 继续跟进给确切时间 第二次又晚了开始警惕是不是在忽悠 要求提供物流凭证 启动备选 第三次连续三次都没到列入黑名单 重点监控 派驻厂协助 开发备选供应商 排产时备注高风险物料"
analysis[48] = "【核心逻辑】物料齐套率=衡量物料管理水平的关键指标。\n\n【为何高达98%-99%】原因一物料种类相对少相比电子厂几千种物料CNC厂的物料很简单 铝材3-5种规格覆盖80%产品 刀具几十种大部分通用 包材/辅料标准化程度高 原因二通用性强 Φ65的铝棒可以做十几种产品 D10刀片几乎所有产品都能用 一种料缺了可以用在很多产品上不容易专料缺 原因三采购周期可控 铝材常规规格现货3天内 常用刀本地代理商有库存 只有非标刀具需定制2-4周\n\n98%-99%意味着100个工单可能有1-2个因物料问题不能按时开工靠安全库存和紧急采购解决\n\n【对比电子厂齐套率可能只有90%-95%物料种类太多芯片电阻电容PCB连接器任何一个缺了都不能组装】"
analysis[49] = "【核心逻辑】物控MC是一个系统工程要从多个维度同时发力。\n\n【六大抓手】①ABC分类 A类价值高影响大每周盘点 B类中等半月盘点 C类价值低一月盘点 ②安全库存 铝棒7天 常用刀3天 包材5天 安全库存=最大日用量×最长补货天数+缓冲 ③呆滞料分析每月做 超90天没动过的 为什么呆滞？停产/BOM变更/买多了 处理 退供应商/折价/内消/报废 ④需求预测 每周五给主要供应商发下周预测 让供应商提前备 ⑤异常快速 来料2h内判定处置方案 制程当日反馈至采购 ECN 24h内完成旧料处置和新料到位 ⑥ECN执行 变更48h内完成旧冻结/新到位/BOM更新/工单投料变更\n\n【好的物控不是不出问题是出现问题后能在最短时间内解决且不复发】"
analysis[50] = "【核心逻辑】MRP=物控核心算法懂原理才能做好MC。\n\n【实例】下周生产P007 2000件 需采购多少铝棒？\n公式展开 净需求=毛需求-现有库存-在途+安全库存 毛需求2000×0.8=1600kg 现存300 在途PO周三到500 安全库存200 损耗率4% MPQ=500kg MOQ=整包(一根约10kg)\n计算 净需求=1600-300-500+200=1000kg 考虑损耗=1000÷0.96=1042kg 向上取整到MOQ=1050kg约105根\n最终下单订购Φ65×100的6061铝棒105根约1050kg 到料要求 生产下周一→物料必须在本周五或周六到 留1-2天做IQC检验 万一到料有品质问题还有时间换货\n\n【铁律物料最好提前5-7天到厂】"
analysis[51] = "【核心逻辑】排产是生管的职责跟单的职责是监督执行分工明确。\n\n【分工】生管经理负责 接到市场和订单/订单评估产能和物料/制定周/日生产计划 哪天做哪个产品用哪几台机台做多少量 发布给各部门\n跟单你负责 拿到计划后逐款复核执行情况 P007计划今天做200件 #01-04机台在做现在产出多少 #05机台怎么停了什么原因什么时候恢复 发现偏差后推动解决 异常升级解决不了的报给经理\n\n【具体复核】每天上午走一遍所有在产机台核对实际vs计划 A型180/200 90%✓ B型60/100 60%✗要关注 C型55/50 110%✓超产也好\n\n【为什么跟单不做排产】排产需要全局视角所有产品优先级所有机台负载所有物料到货情况 这是经理级工作 跟单聚焦在执行层面确保计划落地"
analysis[52] = "【核心逻辑】计划员四大能力=这个岗位的胜任力模型。\n\n【能力模型】执行力30%说了的事要做到布置的任务要落实 体现每2h巡线雷打不动日报准时报异常即时响应 反面拖延遗漏需要人催\n\n异常处理30%出问题时能快速定位协调资源推动解决 体现设备停机能1h内找到ME来修 欠料能追踪到司机位置 反面只上报不推动等人救\n\n细心20%数据准确不出错注重细节 体现报表从未出错工单号码不混BOM核对仔细 反面数字经常算错规格搞混忘记跟进\n\n吃苦耐劳20%能承受工作强度和压力 体现愿意跟夜班加班到深夜不抱怨 反面到点就走不愿意多付出\n\n【面试官最看重】新人来说执行力>吃苦耐劳>细心>异常处理后者可培养"
analysis[53] = "【核心逻辑】PMC=公司运营的中枢神经系统。\n\n【角色定位】如果工厂是军队 厂长总司令定战略方向 PMC参谋长制定作战计划调配资源 生产部前线作战部队执行生产 采购仓库后勤保障部队供弹供粮 品质军纪督察把控质量关 业务外交官对接客户\n\nPMC具体作用①指挥生产决定做什么什么时候做做多少 ②控制物料决定买什么买多少什么时候到 ③平衡供需客户要货vs工厂产能匹配两者 ④控制成本库存太多压资金太少怕断产找平衡点\n\nMC用数据说话 物料齐套率98%→管理水平 库存周转率年12次→资金利用效率 呆滞占比<3%→浪费程度\n\n【一句话总结PMC确保公司在合适时间用合适成本生产合适数量合适产品准时交给客户】"
analysis[54] = "【核心逻辑】LT交货周期=从接单到交货的全链条时间。\n\n【各类产品LT】有库存无表面处理的CNC件5-7天 排产1天+CNC加工2-3天+检验包装1天+缓冲1-2天 有表面处理10-12天 上述5-7天+外发表面3-5天+往返1天\n无库存需从零开始 无表面处理18-22天 采购铝棒3-5天+排产1天+加工2-3天+检验1天+缓冲 有表面处理23-28天 上述18-22天+表面3-5天\n注塑厂对比 有粒子料约2周14天 排产2-3天+注塑3-5天+检验2天+缓冲 无粒子料4-5周28-35天 采购国产1周进口2-3周+上述2周\n\n【回答技巧LT取决于是否有库存和是否需要表面处理一般在5-25天之间 绝不为了接单乱承诺】"
analysis[55] = "【核心逻辑】ECN工程变更通知=制造业最常见的变更流程。\n\n【实例】客户反馈P007跌落测试边角易开裂要求R角R0.5增加到R1.0\nStep1工程发起ECN-20230815-001 变更对象P007 内容R0.5→R1.0 原因客户跌落测试失败 生效8月20日\nStep2 BOM更新 旧D10R0.5铣刀→新D10R1.0铣刀或调整程序参数 如果换料旧MAT-A→新MAT-B\nStep3 ERP投料变更对已开工未完成工单做投料变更 MO领料MAT-A变更为MAT-B 系统路径生产工单→用料清单→变更\nStep4旧料处置剩余库存冻结不能再发到生产线 退供应商or报废or降级使用\n\n【跟单注意ECN生效后确认所有在产工单都完成了投料变更否则会用错误物料继续生产】"
analysis[56] = "【核心逻辑】数据透视=从杂乱原始数据中提取有价值信息。\n\n【两大应用场景】\n场景一汇总多库位库存 同一种D10刀片分散在ABC三区各位置账面数量不同想知总数 从ERP导出物料明细含编码名称库位数量 插入透视表行物料编码值求和数量 还可拖入库位看分布\n\n场景二汇总订单交货 客户华为每月好几批想统计本月总共交多少还欠多少 导出销售订单和出货明细 VLOOKUP匹配订单号 透视表分析行产品型号值求和-订单数-已出货-未出货 一张表看清所有产品交货完成情况\n\n【原始数据是一堆数字透视之后就是管理层看的决策依据】"
analysis[57] = "【核心逻辑】生管和物控是PMC的两个翅膀缺一不可但又各有侧重。\n\n【对比表】维度 生管PC 物控MC 关注焦点 生产计划/产能 物料/库存 核心输入 销售订单/预测 生产计划/BOM 核心输出 生产工单 采购申请PR 考核指标 计划达成率 齐套率/周转率 需要能力 全局观/前瞻性 数据敏感度 日常活动 排产/协调/开会 下PR/盯到货 影响范围 制造成本 库存资金占用\n\n生管更需要全局观能看到所有产品所有机台所有工序全局画面 前瞻性能预判下周月产能瓶颈在哪 沟通协调能推动生产品质工程各部门配合\n物控更需要数据敏感能从一堆数字中发现异常某物料库存突然升高周转率下降 Excel能力VLOOKUP透视表图表是日常工具 细致严谨物料差一个零就是几千块差异\n\n【理想状态生管和物控紧密配合信息共享共同为交付目标负责】"
analysis[58] = "【核心逻辑】持续学习=从跟单到计划员物控的晋升之路。\n\n【学习路径】第一阶段本职深耕前3月 金蝶云星空所有模块摸熟 Excel从SUM/AVERAGE进阶到VLOOKUP/Index-Match/透视表 熟悉CNC全部工艺流程和常见异常\n第二阶段横向拓展第4-6月 主动跟经理请教排产思路和方法论 学习物控如何计算需求和下PR 了解成本核算基本逻辑 材料人工制造费用 网上找电子厂汽车零部件厂PMC资料对比学习\n第三阶段工具进阶第7月及以后 Excel高阶IF嵌套Index-Match组合条件格式 正在学习Power BI做可视化报表给经理看动态仪表盘 计划学Python自动化自动导ERP数据+生成报表 VBA也在计划中宏录制一键刷新\n\n【为什么这么拼不想一直做跟单目标3年内成为独当一面的计划员物控 这行业变化快不学习就会被淘汰】"
analysis[59] = "【核心逻辑】没被提拔=有合理的客观原因不要归咎于自己能力不行。\n\n【标准回答】原因一公司业务萎缩没新增岗位 我们厂今年订单减30%老板缩编制不仅没有新增位置原来助理都裁了 内部没上升通道\n原因二现任生管短期内不会离职 李经理在公司3年和老板关系好近期不离职 他不走我没法顶替\n原因三公司规模小层级少 我们厂200人就两人一个生管一个跟单 没有资深跟单→初级计划员的中间台阶 要么一直做要么等生管走了直接顶\n\n补充说明所以我才想到外面看看机会 我希望找到更有发展空间的平台能够系统学习计划或物控专业知识而不只停留在跟单执行层面\n\n【好处全是客观原因不是主观问题 暗示找到了更好机会自信 表达了学习和发展的愿望上进】"
analysis[60] = "【核心逻辑】转岗采购=利用已有经验降低门槛重点展示对接能力。\n\n【回答】虽然之前职位是跟单但我每天都在和采购打交道 ①催物料每天都要跟采购确认刀具铝棒到货情况延期了我比谁都急 ②跟踪物流有过供应商司机的电话直接跟踪物料到哪里了 ③协调交期和采购一起开过物料协调会讨论怎么解决欠料 ④了解供应商知道主要有哪些分别供什么料大概价格区间\n我们厂大概12-15家供应商 铝材2家主力1+备选1 刀具4-5家不同品类不同供应商 包材辅料3-4家 其他2-3家\n我相信从跟单转采购最大优势是我已经知道了物料对生产的影响哪种急哪种缓供应商信用怎么样 这些经验可以帮助我更好地做采购决策和供应商管理"
analysis[61] = "【核心逻辑】插单急单处理=有限资源下的优先级博弈。\n\n【实例】业务突然插华为急单2000件P010后天交货\n情况A有空闲机台 查#21-#25刚好空的治具现成的 铝棒库存够(仓库存300kg只需160kg) 直接发消息组长#21-#25开P010后天交急 收到马上安排 5分钟搞定\n情况B生产负荷满了更常见 所有机台满负荷 我的步骤 ①先看业务能不能推 这个急单一定要后天吗能不能延到大后天有空档 业务说不行 ②再看哪些订单可后推 P008交期下周一还有5d余量可后延2d ③找生产主管沟通 李主管华为插2000件后天交 我想把P008后延2d腾#21-#25给急单你看行不行 ④主管觉得为难 请业务施压 华为说如果不按时交影响新品发布会能不能帮忙协调 ⑤最终方案 P008延2d+#21-#25做急单+一班夜班追赶P008进度"
analysis[62] = "【核心逻辑】淡旺季应对=用计划平滑需求波动。\n\n【管理方案】信息来源 每两周和市场部对齐未来3-6月预测 每月产销协调会业务+生产+采购+计划+品质 关注行业动态消费电子Q3-Q4旺季新品上市季 Q1-Q2淡季\n人力计划 保持最低正式工约130人满足淡季70%产能 旺季缺口40人用劳务派遣招临时工灵活成本低旺季结束可退 或联系技校安排实习生\n生产计划 淡季安排设备保养员工培训5S整顿 旺季前一个月逐步增加排产量提前爬坡 旺季全员满负荷+两班倒+周六加班\n物料计划 淡季降低安全库存水位减少资金占用 旺季前提前2-3月增加备货长周期物料 旺季中密切监控库存消耗防断料\n\n【核心思想用固定核心+弹性补充的模式应对需求波动既保证旺季产能又不至于淡季养闲人】"
analysis[63] = "【核心逻辑】年产值=公司规模的直观体现回答合理且留余地。\n\n【估算逻辑】年产值=月均产量×平均单价×12月\n200人CNC厂合理范围 保守2000-3000万/年 月产80-120万单价2.5元小型CNC件 正常4000-6000万/年 月产350-500万单价10元中型精密件 乐观8000万-1亿/年 月产700-900万单价10-15元高附加值\n回答模板 我们厂大概200人年产值应该4000万-6000左右吧 具体财务数据我不太清楚只是个小跟单偶尔听经理提起过\n\n【说太精确明显是编的说我不知道显得完全不关心 说个范围+承认不完全掌握=诚实又有认知]\n\n规模参考 100人1500-3000万 200人3000-6000万 500人8000万-1.5亿 1000人2亿-4亿"
analysis[64] = "【核心逻辑】急料定义=时间紧迫+无库存两个条件同时满足。\n\n【判定标准】标准一时间紧迫 明天要用今天必须到 今天上午要用昨夜就应到了 今天下午要用上午必须到\n标准二无库存可用 ERP查可用库存=0 在途还没到或到了未检验 已被其他工单锁定账上有但已被别的订单占了\n举例 周一上午10点 D10合金刀片库存8片 #01-#04今各需2片=需10片 缺2片→急料 Φ65铝棒库存500kg本周需300g→不急 特种非标刀具定制库存0 PO周三到 但#06机台明天要用→急料\n\n【ERP快速查急料 运行物料需求计划报告 筛选需求日期≤明天且可用库存≤0的物料 按紧急程度排序处理\n越常用的料越不容易急因为有安全库存 越特殊的料越容易急因为没有备胎】"
analysis[65] = "【核心逻辑】不良品处置=追溯原因+分类处理+系统同步。\n\n【A换B的不良品处理实例】P007原用MAT-A铝棒ECN换MAT-B 发现用MAT-A做的半成品批量尺寸超差\nStep1原因分析 来料不良？拿材质报告IQC检验合格不是 制程不良？同样程序用MAT-B就没问题是材料适配性问题 ECN通知及时发了提前一周 结论制程不良材料适配性\nStep2不良品处置 数量约150件半成品第1序完第2序发现超差 能否返工？超差0.05mm可通过增加精修挽救→选返工 不能返工打入不良仓等最终处置报废/降价/特采\nStep3系统操作 ERP退料单将MAT-A领料从工单退回 ERP重新领料MAT-B重新生产 工单追加返工额外工时记备注\n\n【如果反过来来料不良 直接整批退回供应商补发MAT-B 系统同样是退A领B 关键无论什么原因不良品都要在系统中留完整处置记录便于追溯和成本核算】"
analysis[66] = "【核心逻辑】急单无料=PMC极限考验穷尽一切方案后给最优解。\n\n【极限操作】周五下午3点业务来电华为急单2000件P010必须周一上午9点交货 查库存Φ80铝棒库存0 PO下周一到 差2000kg D12R0.3刀片库存5片需40片差35片 都无替代品\n方案穷举 方案1找其他料凑 仓库翻遍发现一批Φ85另一个产品的料 能不能车成Φ80？技术员说可以但浪费大且多一道工序不划算放弃 方案2相似评估附近兄弟厂有没有Φ80？电话问有300kg只够300件杯水车薪 能不能用Φ80不同品牌？品质工程需要验证时间来不及 方案3供应商特殊处理 主供应商佛山正常发货2d 打电话老板江湖救急能不能直达车我出运费 同意周六上午发周日凌晨到 刀片东莞本地 能不能派人选过来我出打车费周六下午送到\n方案4如果以上都不行 X经理这个急单因为物料最早周二能交货周一交不了 但我已做了方案123努力 您看能否和客户沟通延后一天或先交一部分\n\n【PMC的价值不是每次都能完美解决而是在极限情况下给出最佳方案让所有人都看到你的努力】"
analysis[67] = "【核心逻辑】工单清尾=确保每个工单有始有终不留尾巴。\n\n【流程】MO20230815001 P007计划200件 生产完后只有185件合格15件不良\nStep1评估不良品 8件尺寸超差0.02mm轻微 7件表面刀痕较严重\nStep2处置 8件轻微超差返工可行重新上机精修2h QA复检6合格2仍不合格 7件刀痕严重无法返工 请QA工程评估外观瑕疵不影响功能可以特采 仍不合格2件+不能特采的报废\nStep3补料 最终185+6+5=196还差4件达200 需重新投产4件 检查物料铝棒刀片有剩余不需重申购 开补料单超领单从原有领料再领少量 安排机台补产约30min完成4件 补产完成后检验入库\nStep4系统结案实际产出196含特采5 不良/报废4 损耗率(200-196)/200=2%低于标准4%表现不错 工单已结案\n\n【不清尾的危害未结案工单持续占用物料账目和产能统计导致库存不准产能计算偏差】"
analysis[68] = "【核心逻辑】提升计划达成率=全方位管理体系不是单一手段。\n\n【五步法】Step1计划合理性排计划时每次排周计划后拉着生产主管一起过一遍 李主管这周的排产你觉得有没有问题哪些机台负荷太重 让生产方认同计划执行才有动力 不认同当场调整避免扯皮\nStep2周会通报每周一早晨召集生产品质工程计划品质开周例会上周达成率多少哪些没达标原因 本周重点关注什么风险点 让所有人同一信息面\nStep3日会复盘每天早上9点 15min站立会 昨天达成率落后多少什么原因 今天的计划有没有特别注意 当天问题当天暴露当天解决\nStep4每2h跟进生产过程中 这是日常核心 10:00 12:00 14:00 16:00四次巡线 每次记录实际vs计划 落产超10%立即干预\nStep5异常快速推动 黄金时间30min内 30分能解决=小问题 30分不能=升级主管经理 绝不让异常过夜\n\n【效果实施前82%实施三月稳定96%关键不是某一个步骤而是五个形成闭环】"
analysis[69] = "【核心逻辑】成品入库延迟=信息流和实物流的不同步两边都抓。\n\n【两种典型原因】\n原因一人员执行偏差最常见 产品下午3点做完但ERP晚上8点才录入 为什么 物料员拉到仓库后忙别的忘了通知生产文员 仓管收到了但没及时扣账 物料员仓管都觉得对方会处理结果都没处理\n推行见单入库制度 生产打好入库单跟随实物送仓库 仓管见入库单+实物才办理 没有入库单一律不收货\n\n原因二流程衔接断层 产品下午3点做好了但晚上7点才入库 时间花在哪 3:00完工→3:30应送到QA 但QA在处理另一批→4:30才开始检本批 QA检验要2h→6:30检完 QA盖章才能入库→7:00完成\n规定时效 成品到QA 4h内开始检验最迟7:00前必须开始 检验完成8h内完成最迟当日16:00前必须完成 超时的纳入绩效\n\n【跟单终极责任我不只看系统入库数据还会去仓库实地确认实物是否真的入库了 只有系统+实物都完成了这道题才算闭合】"
analysis[70] = "【核心逻辑】计划覆盖周期=平衡确定性和灵活性的滚动规划。\n\n【CNC厂覆盖3-4周】 未来3天95%固定几乎不变除非重大异常 第4-7天80%固定可能有小的急单插入 第2周60%固定根据实际和新订单动态调 第3周30%固定大框架具体排产待定 第4周20%固定只有粗略产能分配\n为什么不排更长 越远不确定性越大客户可能取消变更订单 排太死了反而没灵活性应对变化 物料采购一般提前2-3周下单覆盖3-4周够了\n注塑厂覆盖4-5周 注塑工艺相对简单计划调整频率更低 但订单往往批量更大交期更长覆盖周期更长 前1周几乎不变第2周可能有调第3-5周逐渐递减固定度\n\n【滚动概念每周四做下周详细计划同时更新第3-4周框架 不是一次排死一月而是每周向前滚动更新 既保近期准确性又对远期有大致把握】"
analysis[71] = "【核心逻辑】品质争议=不站队用技术和数据说话。\n\n【实例】生产说这批货可以出货品质坚持要返工 争议点P007平面度公差±0.05mm实测0.05-0.07部分超0.02mm 生产观点超差很小不影响没必要返工4h 品质观点超差就是超差不符合图纸就不能出货\n我的处理 Step1不站队不说谁对谁错先看具体情况 Step2拉第三方评估 找工程研发PE来看 这个0.02mm超差对装配功能有影响吗 工程师拿出装配图和功能规格书 外观面0.02肉眼不可见可能特采 配合面0.02可能导致装配干涉必须返工 Step3做验证取10件超差品装配测试 10件中8件顺利2件轻微干涉 有一定风险 Step4和客户沟通 X经理这批有0.02mm超差做了装配测试10件中有2件轻微干涉 您看这批特采还是挑出那2件返工 让客户做最终决定 Step5判定确实有问题 停止该型号生产 排查程序刀具材料问题 修复根源后再恢复\n\n【原则品质问题永远是品质部门有最终否决权但计划部门要做好各方协调和信息传递】"
analysis[72] = "【核心逻辑】产能不足=多管齐下的系统工程单一手段难奏效。\n\n【月产能5000万vs订单8000万缺口3000万37.5%\n\n方案一外发最快见效 把瓶颈工序外发给合作兄弟厂 我们做13序 外发2序 代价外发费+物流+质量管控 适用短期应急\n方案二增人中期见效 正式工130扩到170其中操机员+30白15夜15 品质+5 代价人力成本增约25万/月 注意新人需1-2周培训\n方案三增设备/延长工时立竿见影 100台22h/d延长24h去掉吃饭间隔 周六单班改双班 租赁5-10台二手CNC约2w/台/月 代价租赁费+电费+维护\n方案四工艺优化长期见效 工程优化程序第2序12min降到9min提效25% 引入机械手自动上下料减少辅助50% 改善换型流程2h缩短到1h\n方案五调动积极性软性有效 设立超产奖金超100%按件提成 月度评选产能之星现金+荣誉 团建增强凝聚力\n\n【最佳实践外发+增人+激励组合使用短期+中长期结合】"
