with open('d:/04/trae/1.1/01/pmc/面试宝典/static/data.js', 'r', encoding='utf-8') as f:
    data = json.loads(f.read().replace('export default ', '').rstrip(';\n').strip())

for q in data:
    qid = q['id']
    if qid in analysis:
        q['analysis'] = analysis[qid]
    else:
        print(f'WARNING: No analysis for question {qid}')

with open('d:/04/trae/1.1/01/pmc/面试宝典/static/data.js', 'w', encoding='utf-8') as f:
    f.write('export default ')
    json.dump(data, f, ensure_ascii=False, indent=2)
    f.write(';\n')

print(f'Done! Updated {len(data)} questions.')
print(f'Analysis lengths: min={min(len(q["analysis"]) for q in data)}, max={max(len(q["analysis"]) for q in data)} chars')
